export function getAirportCountry(
  icao: string | null | undefined,
  iata: string | null | undefined,
): string | null {
  if (icao) {
    const v = COUNTRY_BY_ICAO[icao.toUpperCase()];
    if (v) return v;
  }
  if (iata) {
    const v = COUNTRY_BY_IATA[iata.toUpperCase()];
    if (v) return v;
  }
  return null;
}
